/**
 * Bestsellers Routes
 * Handles bestseller list queries
 * Uses Redis to store and query bestseller data
 */

const express = require('express');
const router = express.Router();
const redis = require('redis');
const { promisify } = require('util');
const config = require('../config');

let redisClient = null;
let zrevrangeAsync = null;

// Initialize Redis client
function initRedis() {
  if (config.redis.enabled && !redisClient) {
    try {
      redisClient = redis.createClient({
        host: config.redis.host,
        port: config.redis.port,
        password: config.redis.password,
        retry_strategy: (options) => {
          if (options.error && options.error.code === 'ECONNREFUSED') {
            console.error('Redis connection refused');
            return new Error('Redis server refused connection');
          }
          if (options.total_retry_time > 1000 * 60 * 60) {
            return new Error('Redis retry time exhausted');
          }
          if (options.attempt > 10) {
            return undefined;
          }
          return Math.min(options.attempt * 100, 3000);
        }
      });

      redisClient.on('error', (err) => {
        console.error('Redis error:', err);
      });

      redisClient.on('connect', () => {
        console.log('Redis connected successfully');
      });

      // Convert Redis commands to Promises
      zrevrangeAsync = promisify(redisClient.zrevrange).bind(redisClient);
    } catch (error) {
      console.error('Failed to initialize Redis:', error);
      redisClient = null;
    }
  }
}

// Initialize Redis
initRedis();

/**
 * GET /bestsellers
 * Get Bestsellers List (Top 20)
 */
router.get('/', async (req, res, next) => {
  try {
    // If Redis is not enabled or not connected, return mock data
    if (!config.redis.enabled || !redisClient) {
      console.warn('Redis not available, returning mock data');
      return res.json([]);
    }

    const key = 'TopBooks:AllTime';

    // Get top 20 from leaderboard
    // zrevrange returns members ordered by score from high to low
    const members = await zrevrangeAsync(key, 0, 19);

    // Clean up JSON formatted bookIds
    const bookIds = members.map(member => {
      try {
        return JSON.parse(member);
      } catch (e) {
        return member;
      }
    });

    res.json(bookIds);
  } catch (error) {
    console.error('Error in GET /bestsellers:', error);
    // If Redis error, return empty array instead of error
    res.json([]);
  }
});

module.exports = router;

/**
 * Books Related Routes
 * Handles book query operations
 */

const express = require('express');
const router = express.Router();
const { dynamodb, docClient } = require('../utils/dynamodb');
const { dynamodb: dynamodbConfig } = require('../config');
const authMiddleware = require('../middleware/auth');

const booksTable = dynamodbConfig.booksTable;

/**
 * GET /books
 * List all books or list books by category
 * Query params: category (optional)
 */
router.get('/', async (req, res, next) => {
  try {
    const category = req.query.category;

    if (category) {
      // Query by category
      const params = {
        TableName: booksTable,
        IndexName: 'category-index',
        KeyConditionExpression: 'category = :category',
        ExpressionAttributeValues: {
          ':category': category
        }
      };

      const data = await docClient.query(params).promise();
      res.json(data.Items);
    } else {
      // List all books
      const params = {
        TableName: booksTable
      };

      const data = await docClient.scan(params).promise();
      res.json(data.Items);
    }
  } catch (error) {
    console.error('Error in GET /books:', error);
    next(error);
  }
});

/**
 * GET /books/:id
 * Get detailed info of a single book
 * Path params: id - Book ID
 */
router.get('/:id', async (req, res, next) => {
  try {
    const params = {
      TableName: booksTable,
      Key: {
        id: req.params.id
      }
    };

    const data = await docClient.get(params).promise();

    if (data.Item) {
      res.json(data.Item);
    } else {
      res.status(404).json({ error: 'Book not found' });
    }
  } catch (error) {
    console.error('Error in GET /books/:id:', error);
    next(error);
  }
});

module.exports = router;

