        bookId: bookId,
        quantity: quantity,
        price: price
      }
    };

    await docClient.put(params).promise();
    res.json({ message: 'Item added to cart successfully' });
  } catch (error) {
    console.error('Error in POST /cart:', error);
    next(error);
  }
});

/**
